mapper.select:

from buyer b

where b.buyer_code = #{buyerCode}
limit 1

mapper.insert:
insert into buyer_account(
    buyer_id, dept_id, user_name, nick_name, password, email, phonenumber,
    account_role, status, pwd_update_time, create_by, create_time, remark
) values (
    #{buyerId}, #{deptId}, #{userName}, #{nickName}, #{password}, #{email}, #{phonenumber},
    #{accountRole}, #{status}, sysdate(), #{createBy}, sysdate(), #{remark}
)

insert into buyer_login_log(
    buyer_id, buyer_account_id, user_name, ipaddr, login_location,
    browser, os, status, msg, login_time
) values (
    #{subjectId}, #{accountId}, #{userName}, #{ipaddr}, #{loginLocation},
    #{browser}, #{os}, #{status}, #{msg}, #{loginTime}
)

mapper.select:
select l.info_id, l.buyer_id, l.buyer_account_id, l.user_name, l.ipaddr, l.login_location, l.browser, l.os, l.status, l.msg, l.login_time from buyer_login_log l where 1 = 1
and l.buyer_id = #{subjectId}
and l.buyer_account_id = #{accountId}
and l.user_name like concat('%', #{userName}, '%')
and l.ipaddr like concat('%', #{ipaddr}, '%')
and l.status = #{status}
and date_format(l.login_time,'%Y%m%d') >= date_format(#{params.beginTime},'%Y%m%d')
and date_format(l.login_time,'%Y%m%d') <= date_format(#{params.endTime},'%Y%m%d')
order by l.login_time desc, l.info_id desc

select l.oper_id, l.buyer_id, l.buyer_account_id, l.title, l.business_type, l.method, l.request_method, l.oper_name, l.oper_url, l.oper_ip, l.oper_location, l.oper_param, l.json_result, l.status, l.error_msg, l.oper_time, l.cost_time from buyer_oper_log l where 1 = 1
and l.buyer_id = #{subjectId}
and l.buyer_account_id = #{accountId}
and l.title like concat('%', #{title}, '%')
and l.oper_name like concat('%', #{operName}, '%')
and l.status = #{status}
and date_format(l.oper_time,'%Y%m%d') >= date_format(#{params.beginTime},'%Y%m%d')
and date_format(l.oper_time,'%Y%m%d') <= date_format(#{params.endTime},'%Y%m%d')
order by l.oper_time desc, l.oper_id desc

