mapper.update:
update buyer_session
set status = '1',
    logout_time = sysdate()
where buyer_id = #{buyerId}
  and buyer_account_id = #{buyerAccountId}
  and token_id = #{tokenId}
  and status = '0'
  and logout_time is null
